diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
index fc284bc61cce..381309079132 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAddSub.cpp
@@ -1563,6 +1563,71 @@ Instruction *InstCombinerImpl::visitAdd(BinaryOperator &I) {
     }
   }

+
+  // ((X u/ C) << K) + (X u% C) -> ((X u/ C) * (2^K - C)) + X
+  // This fold is valid when C <= 2^K because the remainder is guaranteed
+  // to not overlap with the shifted quotient bits.
+  {
+    Value *DivVal, *RemVal;
+    const APInt *Divisor, *ShiftAmt;
+    // Match: add(shl(udiv(X, C), K), urem(X, C)) or commuted
+    if (match(&I, m_c_Add(m_OneUse(m_Shl(m_OneUse(m_UDiv(m_Value(DivVal),
+                                                        m_APInt(Divisor))),
+                                              m_APInt(ShiftAmt))),
+                          m_URem(m_Value(RemVal), m_APInt(Divisor)))) &&
+        DivVal == RemVal) {
+      // Check that C <= 2^K (i.e., the remainder fits in the lower K bits)
+      APInt ShiftedDivisor = APInt(Divisor->getBitWidth(), 1) << *ShiftAmt;
+      if (Divisor->ule(ShiftedDivisor)) {
+        // Find and reuse the udiv instruction from the shl operand
+        Value *Shl = I.getOperand(0);
+        BinaryOperator *ShlOp = dyn_cast<BinaryOperator>(Shl);
+        if (!ShlOp) ShlOp = dyn_cast<BinaryOperator>(I.getOperand(1));
+        if (ShlOp && ShlOp->getOpcode() == Instruction::Shl) {
+          Value *Udiv = ShlOp->getOperand(0);
+          Value *Multiplier = ConstantInt::get(Ty, ShiftedDivisor - *Divisor);
+          Value *Mul = Builder.CreateMul(Udiv, Multiplier, "reass.mul",
+                                         /*HasNoSignedWrap=*/false,
+                                         /*HasNoUnsignedWrap=*/true);
+          return BinaryOperator::CreateAdd(Mul, DivVal);
+        }
+      }
+    }
+  }
+
+  // ((X s/ C) << K) + (X s% C) -> ((X s/ C) * (2^K - C)) + X
+  // This fold is valid when |C| <= 2^K because the remainder is guaranteed
+  // to not overlap with the shifted quotient bits (for signed division).
+  {
+    Value *DivVal, *RemVal;
+    const APInt *Divisor, *ShiftAmt;
+    // Match: add(shl(sdiv(X, C), K), srem(X, C)) or commuted
+    if (match(&I, m_c_Add(m_OneUse(m_Shl(m_OneUse(m_SDiv(m_Value(DivVal),
+                                                       m_APInt(Divisor))),
+                                             m_APInt(ShiftAmt))),
+                          m_SRem(m_Value(RemVal), m_APInt(Divisor)))) &&
+        DivVal == RemVal) {
+      // Check that |C| <= 2^K (i.e., the remainder fits in the lower K bits)
+      APInt ShiftedDivisor = APInt(Divisor->getBitWidth(), 1) << *ShiftAmt;
+      APInt AbsDivisor = Divisor->abs();
+      if (AbsDivisor.ule(ShiftedDivisor)) {
+        // Find and reuse the sdiv instruction from the shl operand
+        Value *Shl = I.getOperand(0);
+        BinaryOperator *ShlOp = dyn_cast<BinaryOperator>(Shl);
+        if (!ShlOp) ShlOp = dyn_cast<BinaryOperator>(I.getOperand(1));
+        if (ShlOp && ShlOp->getOpcode() == Instruction::Shl) {
+          Value *Sdiv = ShlOp->getOperand(0);
+          Value *Multiplier = ConstantInt::get(Ty, ShiftedDivisor - *Divisor);
+          Value *Mul = Builder.CreateMul(Sdiv, Multiplier, "reass.mul",
+                                         /*HasNoSignedWrap=*/true,
+                                         /*HasNoUnsignedWrap=*/false);
+          return BinaryOperator::CreateAdd(Mul, DivVal);
+        }
+      }
+    }
+  }
+
+
   // (A & 2^C1) + A => A & (2^C1 - 1) iff bit C1 in A is a sign bit
   if (match(&I, m_c_Add(m_And(m_Value(A), m_APInt(C1)), m_Deferred(A))) &&
       C1->isPowerOf2() && (ComputeNumSignBits(A) > C1->countl_zero())) {
diff --git a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
index e1923a344179..f26e2bb9051e 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineAndOrXor.cpp
@@ -3505,6 +3505,28 @@ Instruction *InstCombinerImpl::visitOr(BinaryOperator &I) {
     Value *IncrementY = Builder.CreateAdd(Y, ConstantInt::get(Ty, 1));
     return BinaryOperator::CreateMul(X, IncrementY);
   }
+  // ((X u/ C) << K) | (X u% C) -> ((X u/ C) * (2^K - C)) + X
+  // This fold is valid when C <= 2^K because the remainder is guaranteed
+  // to not overlap with the shifted quotient bits.
+  {
+    Value *DivVal, *RemVal;
+    const APInt *Divisor, *ShiftAmt;
+    // Match: or(shl(udiv(X, C), K), urem(X, C)) or commuted
+    if (match(&I, m_c_Or(m_Shl(m_UDiv(m_Value(DivVal), m_APInt(Divisor)),
+                                  m_APInt(ShiftAmt)),
+                         m_URem(m_Value(RemVal), m_APInt(Divisor)))) &&
+        DivVal == RemVal) {
+      // Check that C <= 2^K (i.e., the remainder fits in the lower K bits)
+      APInt ShiftedDivisor = APInt(Divisor->getBitWidth(), 1) << *ShiftAmt;
+      if (Divisor->ule(ShiftedDivisor)) {
+        // Transform to: add(mul(udiv(X, C), 2^K - C), X)
+        Value *Udiv = Builder.CreateUDiv(DivVal, ConstantInt::get(Ty, *Divisor));
+        Value *Multiplier = ConstantInt::get(Ty, ShiftedDivisor - *Divisor);
+        Value *Mul = Builder.CreateMul(Udiv, Multiplier, "reass.mul");
+        return BinaryOperator::CreateAdd(Mul, DivVal);
+      }
+    }
+  }

   // (A & C) | (B & D)
   Value *A, *B, *C, *D;

